#include <stdio.h>
#include <stdlib.h>
#define MAXN 75000
#define MAXK 18
int dp[MAXN + 1][MAXN + 1];
int a[MAXN];
int n, m, k;
void update(int idx, int val) {
    for (int i = n; i >= idx; i--) {
        for (int j = 1; j <= i; j++) {
            if (i == idx) {
                dp[i][j] = val;
            } else {
                dp[i][j] = (dp[i - 1][j - 1] & val) > dp[i - 1][j] ? (dp[i - 1][j - 1] & val) : dp[i - 1][j];
            }
        }
    }
}
int main() {
    scanf("%d %d %d", &n, &m, &k);
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
        update(i, a[i]);
    }
    for (int i = 0; i < m; i++) {
        int type, val;
        scanf("%d %d", &type, &val);
        if (type == 1) {
            a[n++] = val;
            update(n - 1, val);
        } else if (type == 2) {
            for (int j = 0; j < n; j++) {
                if (a[j] == val) {
                    for (int p = j; p < n - 1; p++) {
                        a[p] = a[p + 1];
                    }
                    n--;
                    update(j, a[j]);
                    break;
                }
            }
        } else {
            printf("%d\n", dp[n][val]);
        }
    }
    return 0;
}

